WITH temp AS(SELECT b.book_id,b.title,b.author,b.genre,b.pages,r.session_rating FROM books b JOIN reading_sessions r ON b.book_id=r.book_id),aggregated AS(SELECT book_id,title,author,genre,pages,COUNT(*) AS total_sessions,MAX(session_rating) AS highest_rating,MIN(session_rating) AS lowest_rating,(MAX(session_rating)-MIN(session_rating)) AS rating_spread,SUM(CASE WHEN session_rating<=2 OR session_rating>=4 THEN 1 ELSE 0 END) AS extreme_count FROM temp GROUP BY book_id),polarizedbooks AS(SELECT book_id,title,author,genre,pages,rating_spread,ROUND(extreme_count*1.0/total_sessions,2) AS polarization_score FROM aggregated WHERE highest_rating>=4 AND lowest_rating<=2 AND total_sessions>=5)
SELECT book_id,title,author,genre,pages,rating_spread,polarization_score FROM polarizedbooks WHERE polarization_score>=0.6 ORDER BY polarization_score DESC,title DESC
